args.sparql:
SELECT ?lighthouse ?lighthouseLabel WHERE {
  ?lighthouse wdt:P31 wd:Q39715 .
  ?lighthouse wdt:P2048 ?height .
  ?height wikibase:quantityAmount ?value ;
          wikibase:quantityUnit wd:Q11573 .
  FILTER(?value >= 26)
  ?lighthouse rdfs:label ?lighthouseLabel .
  FILTER(LANG(?lighthouseLabel) = "en")
}

SELECT ?lighthouse ?lighthouseLabel WHERE {
  ?lighthouse wdt:P31 wd:Q39715 .
  ?lighthouse wdt:P2048 ?height .
  ?height wikibase:quantityAmount ?value ;
          wikibase:quantityUnit ?unit .
  BIND( (IF(?unit = wd:Q11573, ?value, IF(?unit = wd:Q174280, ?value * 0.3048, -1))) AS ?heightInMeters )
  FILTER(?heightInMeters >= 26)
  ?lighthouse rdfs:label ?lighthouseLabel .
  FILTER(LANG(?lighthouseLabel) = "en")
}

